UPDATE
MST.TB_IP_HOST_MST A
SET
	A.DMODIFY_DT = sysdate 			
	, A.SCOMMENT = #{scomment, jdbcType=VARCHAR}
	, A.SMODELNAME = #{smodelname, jdbcType=VARCHAR}

		, A.NIP_ASSIGN_MST_SEQ = #{nipAssignMstSeq, jdbcType=BIGINT}


		, A.NIP_ALLOC_MST_SEQ = #{nipAllocMstSeq, jdbcType=BIGINT}


		, A.SASSIGN_TYPE_CD = #{sassignTypeCd, jdbcType=CHAR}


		, A.SPRORITY_YN = #{sprorityYn, jdbcType=CHAR}


		, A.SPORTID = #{sportid, jdbcType=VARCHAR}


		, A.NLGIPPORTSEQ = #{nlgipportseq, jdbcType=INTEGER}


		, A.SIP_IF_NM = #{sipIfNm, jdbcType=VARCHAR}


		, A.SNESCODE = #{snescode, jdbcType=VARCHAR}


		, A.SIP_HOST_NM = #{sipHostNm, jdbcType=VARCHAR}


		, A.SRSSOFFICESCODE = #{srssofficescode, jdbcType=CHAR}


		, A.SSAID = #{ssaid, jdbcType=VARCHAR}


		, A.SLLNUM = #{sllnum, jdbcType=VARCHAR}


		, A.SEX_SVC_CD = #{sexSvcCd, jdbcType=VARCHAR}


		, A.SIP_VERSION_TYPE_CD = #{sipVersionTypeCd, jdbcType=CHAR}


		, A.PIP_HOST_INET = #{pipHostInet, javaType=Object, jdbcType=OTHER, typeHandler=com.kt.ipms.legacy.cmn.typehandler.CIDRTypeHandler}


		, A.SIP_BLOCK = #{sipBlock, jdbcType=VARCHAR}


		, A.SNETMASK = #{snetmask, jdbcType=VARCHAR}


		, A.NFIRST_ADDR = #{nfirstAddr, jdbcType=NUMERIC}


		, A.SFIRST_IP_PREFERRED = #{sfirstIpPreferred, jdbcType=VARCHAR}


		, A.SMODIFY_ID = #{smodifyId, jdbcType=VARCHAR}

WHERE 1=1
	AND A.SIP_HOST_TYPE_CD = #{sipHostTypeCd, jdbcType=CHAR}
	AND A.SIP_BLOCK = #{sipBlock, jdbcType=VARCHAR}
